import { GoogleGenAI } from "@google/genai";

const API_KEY = process.env.API_KEY;

if (!API_KEY) {
  throw new Error("API_KEY environment variable not set");
}

const ai = new GoogleGenAI({ apiKey: API_KEY });

const extractDistance = (text: string | undefined): number | null => {
    if (!text) return null;
    const sanitizedText = text.replace(',', '.');
    const distanceMatch = sanitizedText.match(/(\d+(\.\d+)?)/);
    if (distanceMatch) {
        const distance = parseFloat(distanceMatch[0]);
        if (!isNaN(distance) && distance > 0) {
            return distance;
        }
    }
    return null;
};

export const getDistance = async (origin: string, destination: string): Promise<number | null> => {
  const model = 'gemini-2.5-flash';

  const basePrompt = `Tarefa: Calcular a distância de carro (em km) entre "${origin}" e "${destination}".
  Contexto: Minas Gerais, Brasil.

  Instruções Críticas:
  1. O objetivo é obter um valor numérico para cálculo de frete.
  2. Se houver ambiguidade no nome da cidade, assuma que é em Minas Gerais.
  3. Se não encontrar um endereço exato, use o centro da cidade.
  4. PRIORIDADE: Retorne APENAS o número (ex: 150.5). Sem texto adicional.`;

  // Tentativa 1: Usar Google Search (Mais preciso)
  try {
    const response = await ai.models.generateContent({
      model: model,
      contents: basePrompt + "\nUse o Google Search para encontrar a distância rodoviária atualizada.",
      config: {
        tools: [{ googleSearch: {} }],
        temperature: 0.1,
      },
    });

    const distance = extractDistance(response.text?.trim());
    if (distance) return distance;

  } catch (error: any) {
    // Se der erro (ex: 403 Permission Denied ou 400), fazemos fallback
    console.warn("Erro ao usar Google Search (Tentativa 1). Tentando fallback para conhecimento interno.", error);
  }

  // Tentativa 2: Fallback para conhecimento interno do modelo (Sem tools)
  try {
      const response = await ai.models.generateContent({
        model: model,
        contents: basePrompt + "\nEstime a distância com base no seu conhecimento geográfico interno.",
        config: {
            temperature: 0.1,
            // Sem tools para evitar erro de permissão
        },
      });

      const distance = extractDistance(response.text?.trim());
      if (distance) return distance;

      console.error("Não foi possível extrair a distância da resposta de fallback:", response.text);
  } catch (error) {
      console.error("Erro fatal ao chamar API Gemini (Fallback):", error);
  }

  return null;
};

import { GoogleGenAI } from "@google/genai";

/**
 * Função segura para obter a chave de API sem quebrar a execução global
 */
const getApiKey = () => {
  try {
    return process.env.API_KEY;
  } catch (e) {
    return undefined;
  }
};

const extractDistance = (text: string | undefined): number | null => {
    if (!text) return null;
    const sanitizedText = text.replace(',', '.');
    // Busca o primeiro número na resposta
    const distanceMatch = sanitizedText.match(/(\d+(\.\d+)?)/);
    if (distanceMatch) {
        const distance = parseFloat(distanceMatch[0]);
        if (!isNaN(distance) && distance > 0) {
            return distance;
        }
    }
    return null;
};

export const getDistance = async (origin: string, destination: string): Promise<number | null> => {
  const apiKey = getApiKey();

  if (!apiKey) {
    console.error("Gemini API Key não encontrada em process.env.API_KEY. O cálculo de rota será desabilitado.");
    return null;
  }

  // Modelo recomendado para tarefas de texto/busca
  const modelName = 'gemini-3-flash-preview';

  const basePrompt = `Tarefa: Calcular a distância de carro (em km) entre "${origin}" e "${destination}".
  Contexto: Minas Gerais, Brasil.

  Instruções Críticas:
  1. O objetivo é obter um valor numérico para cálculo de frete.
  2. Se houver ambiguidade no nome da cidade, assuma que é em Minas Gerais (Brasil).
  3. Se não encontrar um endereço exato, use o centro da cidade ou ponto de referência.
  4. PRIORIDADE: Retorne APENAS o número (ex: 150.5). Sem texto adicional, sem unidade "km".`;

  // Tentativa 1: Usar Google Search (Maior precisão para rotas reais)
  try {
    const ai = new GoogleGenAI({ apiKey });
    const response = await ai.models.generateContent({
      model: modelName,
      contents: basePrompt + "\nUse o Google Search para encontrar a distância rodoviária exata e atualizada.",
      config: {
        tools: [{ googleSearch: {} }],
        temperature: 0.1,
      },
    });

    const distance = extractDistance(response.text?.trim());
    if (distance) return distance;

  } catch (error: any) {
    console.warn("Aviso: Falha ao usar Google Search para distância. Tentando fallback interno.", error);
  }

  // Tentativa 2: Fallback para o conhecimento geográfico interno do modelo
  try {
      const ai = new GoogleGenAI({ apiKey });
      const response = await ai.models.generateContent({
        model: modelName,
        contents: basePrompt + "\nEstime a distância rodoviária aproximada com base no seu conhecimento de mapas e rotas de Minas Gerais.",
        config: {
            temperature: 0.1,
        },
      });

      const distance = extractDistance(response.text?.trim());
      if (distance) return distance;

      console.error("Não foi possível extrair um número válido da resposta do Gemini:", response.text);
  } catch (error) {
      console.error("Erro fatal ao chamar a API Gemini:", error);
  }

  return null;
};

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');

if (!rootElement) {
  console.error("Elemento raiz 'root' não encontrado no HTML.");
} else {
  try {
    const root = ReactDOM.createRoot(rootElement);
    root.render(
      <React.StrictMode>
        <App />
      </React.StrictMode>
    );
  } catch (error) {
    console.error("Erro crítico ao renderizar o aplicativo:", error);
    // Fallback visual simples em caso de erro catastrófico de renderização
    rootElement.innerHTML = `
      <div style="display: flex; flex-direction: column; align-items: center; justify-content: center; height: 100vh; font-family: sans-serif; text-align: center; padding: 20px;">
        <h1 style="color: #e53e3e;">Erro de Inicialização</h1>
        <p style="color: #4a5568;">Ocorreu um erro ao carregar o aplicativo. Por favor, tente recarregar a página.</p>
        <button onclick="window.location.reload()" style="padding: 10px 20px; background: #ecc94b; border: none; border-radius: 5px; cursor: pointer; font-weight: bold;">Recarregar</button>
      </div>
    `;
  }
}

import React, { useState } from 'react';
import type { User } from '../types';
import * as authService from '../services/authService';

interface AuthPageProps {
  onLoginSuccess: (user: User) => void;
}

const AuthPage: React.FC<AuthPageProps> = ({ onLoginSuccess }) => {
  const [isLoginView, setIsLoginView] = useState(true);
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');
  const [error, setError] = useState<string | null>(null);
  const [success, setSuccess] = useState<string | null>(null);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setError(null);
    setSuccess(null);

    if (isLoginView) {
      const result = authService.login(email, password);
      if (result.success && result.user) {
        onLoginSuccess(result.user);
      } else {
        setError(result.message);
      }
    } else {
      if (password !== confirmPassword) {
        setError('As senhas não coincidem.');
        return;
      }
      const result = authService.register(email, password);
      if (result.success) {
        setSuccess('Cadastro realizado com sucesso! Faça o login para continuar.');
        setIsLoginView(true);
        setEmail('');
        setPassword('');
        setConfirmPassword('');
      } else {
        setError(result.message);
      }
    }
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-gray-100 dark:bg-gray-900 p-6">
      <div className="w-full max-w-xl bg-white dark:bg-gray-800 rounded-xl shadow-2xl p-10 sm:p-14">
        <div className="text-center mb-12">
          <h1 className="text-5xl font-bold text-gray-800 dark:text-white">TABELA TÁXI</h1>
          <p className="text-2xl text-gray-600 dark:text-gray-300 mt-4">
            {isLoginView ? 'Bem-vindo de volta' : 'Crie sua conta'}
          </p>
        </div>

        <form onSubmit={handleSubmit} className="space-y-8">
          <div>
            <input
                type="text"
                placeholder="E-mail ou 'Admin'"
                value={email}
                onChange={(e) => setEmail(e.target.value)}
                className="w-full px-6 py-5 text-2xl bg-gray-50 dark:bg-gray-700 border border-gray-300 dark:border-gray-600 rounded-xl text-gray-800 dark:text-gray-200 focus:outline-none focus:ring-4 focus:ring-blue-500/50"
                required
            />
          </div>
          <div>
            <input
                type="password"
                placeholder="Senha"
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                className="w-full px-6 py-5 text-2xl bg-gray-50 dark:bg-gray-700 border border-gray-300 dark:border-gray-600 rounded-xl text-gray-800 dark:text-gray-200 focus:outline-none focus:ring-4 focus:ring-blue-500/50"
                required
            />
          </div>
          {!isLoginView && (
            <div>
                <input
                type="password"
                placeholder="Confirmar Senha"
                value={confirmPassword}
                onChange={(e) => setConfirmPassword(e.target.value)}
                className="w-full px-6 py-5 text-2xl bg-gray-50 dark:bg-gray-700 border border-gray-300 dark:border-gray-600 rounded-xl text-gray-800 dark:text-gray-200 focus:outline-none focus:ring-4 focus:ring-blue-500/50"
                required
                />
            </div>
          )}

          {error && <p className="text-red-500 text-xl text-center font-bold bg-red-100 p-3 rounded">{error}</p>}
          {success && <p className="text-green-500 text-xl text-center font-bold bg-green-100 p-3 rounded">{success}</p>}

          <button
            type="submit"
            className="w-full bg-blue-600 text-white font-extrabold py-5 px-8 rounded-xl hover:bg-blue-700 transition-colors duration-300 shadow-lg text-2xl uppercase tracking-wide"
          >
            {isLoginView ? 'Entrar' : 'Cadastrar'}
          </button>
        </form>

        <div className="text-center mt-10">
          <button
            onClick={() => {
                setIsLoginView(!isLoginView);
                setError(null);
                setSuccess(null);
            }}
            className="text-xl text-blue-600 hover:text-blue-700 hover:underline font-semibold"
          >
            {isLoginView ? 'Não tem uma conta? Cadastre-se' : 'Já tem uma conta? Faça login'}
          </button>
        </div>
      </div>
    </div>
  );
};

export default AuthPage;

