const FareTable: React.FC<FareTableProps> = ({ fares, isAdmin, searchTerm, setSearchTerm, onAddFare, onUpdateFare, onDeleteFare, onImportFares }) => {
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [editingFare, setEditingFare] = useState<Fare | null>(null);
    const fileInputRef = useRef<HTMLInputElement>(null);

    const handleAdd = () => {
        if (!isAdmin) return;
        setEditingFare(null);
        setIsModalOpen(true);
    };

    const handleEdit = (fare: Fare) => {
        if (!isAdmin) return;
        setEditingFare(fare);
        setIsModalOpen(true);
    };

    const handleDelete = (id: string) => {
        if (!isAdmin) return;
        if (window.confirm('Tem certeza que deseja excluir esta corrida?')) {
            onDeleteFare(id);
        }
    };

    const handleSave = (fare: Fare) => {
        if (!isAdmin) return;
        if (editingFare) {
            onUpdateFare(fare);
        } else {
            onAddFare(fare);
        }
        setIsModalOpen(false);
        setEditingFare(null);
    };

    const handleImportClick = () => {
        if (!isAdmin) return;
        fileInputRef.current?.click();
    };

    const handleExport = () => {
        if (!isAdmin) return;
        if (fares.length === 0) {
            alert("Não há dados na tabela para exportar.");
            return;
        }

        const header = "Destino,Regiao,ValorTaximetro,ValorBalcao\n";
        const csvRows = fares.map(fare => {
            const destination = `"${fare.destination.replace(/"/g, '""')}"`;
            const region = `"${fare.region.replace(/"/g, '""')}"`;
            const meterValue = fare.meterValue.toFixed(2);
            const counterValue = fare.counterValue.toFixed(2);
            return [destination, region, meterValue, counterValue].join(',');
        }).join('\n');

        const csvContent = "\uFEFF" + header + csvRows;
        const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
        const link = document.createElement("a");
        const url = URL.createObjectURL(blob);
        link.setAttribute("href", url);
        const timestamp = new Date().toISOString().slice(0, 10).replace(/-/g, '');
        link.setAttribute("download", `export_tabela_taxi_${timestamp}.csv`);
        document.body.appendChild(link);
        link.click();

        document.body.removeChild(link);
        URL.revokeObjectURL(url);
    };

    const handleFileChange = (event: React.ChangeEvent<HTMLInputElement>) => {
        if (!isAdmin) return;
        const file = event.target.files?.[0];
        if (!file) return;

        const reader = new FileReader();
        reader.onload = (e) => {
            const text = e.target?.result as string;
            if (!text) return;

            try {
                const lines = text.split('\n').filter(line => line.trim() !== '');
                const newFares: Fare[] = lines.slice(1)
                    .map((line, index) => {
                        const [destination, region, meterValueStr, counterValueStr] = line.split(',');
                        if (!region || !destination || !meterValueStr || !counterValueStr) return null;

                        const meterValue = parseFloat(meterValueStr.trim());
                        const counterValue = parseFloat(counterValueStr.trim());

                        if (isNaN(meterValue) || isNaN(counterValue)) return null;

                        return {
                            id: `imported-${new Date().getTime()}-${index}`,
                            region: region.trim(),
                            destination: destination.trim(),
                            meterValue,
                            counterValue,
                        };
                    }).filter((fare): fare is Fare => fare !== null);

                if (newFares.length > 0) {
                    onImportFares(newFares);
                    setSearchTerm('');
                    alert(`${newFares.length} corridas importadas com sucesso!`);
                } else {
                    alert('Nenhuma corrida válida encontrada no arquivo.');
                }
            } catch (error) {
                console.error("Erro ao processar o arquivo CSV:", error);
                alert('Erro ao processar o arquivo CSV.');
            }
        };
        reader.readAsText(file);
        event.target.value = '';
    };

  return (
    <div className="bg-transparent">
       {isModalOpen && <FareModal fare={editingFare} onSave={handleSave} onClose={() => setIsModalOpen(false)} />}
      <div className="flex flex-col xl:flex-row justify-between items-center mb-6 gap-4 p-4 sm:p-6 bg-white rounded-xl shadow-md">
        <h2 className="text-xl sm:text-2xl font-bold text-gray-800 shrink-0">Bairro/Hotel</h2>
        <div className="w-full xl:w-auto flex flex-col xl:flex-row items-center gap-4">
            <div className="relative w-full xl:w-80">
                <input
                    type="text"
                    placeholder="Buscar por região ou destino..."
                    value={searchTerm}
                    onChange={(e) => setSearchTerm(e.target.value)}
                    className="w-full pr-10 pl-4 py-2 text-base border border-gray-300 rounded-full focus:outline-none focus:ring-2 focus:ring-yellow-400 transition"
                />
                {searchTerm && (
                    <button 
                        onClick={() => setSearchTerm('')}
                        className="absolute right-3 top-1/2 -translate-y-1/2 p-1 text-gray-400 hover:text-gray-600 focus:outline-none"
                    >
                        <XIcon className="w-5 h-5" />
                    </button>
                )}
            </div>
            {isAdmin && (
                <div className="flex items-center gap-2 justify-center w-full xl:w-auto">
                    <input type="file" ref={fileInputRef} onChange={handleFileChange} className="hidden" accept=".csv" />
                    <button onClick={handleImportClick} className="p-2 bg-blue-500 text-white rounded-full hover:bg-blue-600 shadow-sm" title="Importar">
                        <UploadIcon className="w-6 h-6" />
                    </button>
                    <button onClick={handleExport} className="p-2 bg-gray-500 text-white rounded-full hover:bg-gray-600 shadow-sm" title="Exportar">
                        <DownloadIcon className="w-6 h-6" />
                    </button>
                    <button onClick={handleAdd} className="flex items-center justify-center bg-yellow-500 text-white font-bold py-2 px-4 rounded-full hover:bg-yellow-600 shadow-sm text-sm">
                        <PlusIcon className="w-5 h-5 mr-1" />
                        Adicionar
                    </button>
                </div>
            )}
        </div>
      </div>

      <div className="mt-4 md:bg-white md:rounded-xl md:shadow overflow-hidden">
        <table className="min-w-full">
            <thead className="hidden md:table-header-group bg-gray-100">
                <tr>
                    <th className="px-6 py-4 text-left text-sm font-bold text-gray-600 uppercase">Destino</th>
                    <th className="px-6 py-4 text-left text-sm font-bold text-gray-600 uppercase">Região</th>
                    <th className="px-6 py-4 text-left text-sm font-bold text-gray-600 uppercase">Taxímetro</th>
                    <th className="px-6 py-4 text-left text-sm font-bold text-gray-600 uppercase">Balcão</th>
                    {isAdmin && <th className="px-6 py-4"></th>}
                </tr>
            </thead>
            <tbody className="divide-y divide-gray-200">
                {fares.length > 0 ? fares.map((fare) => (
                    <tr key={fare.id} className="block md:table-row mb-4 md:mb-0 bg-white rounded-xl shadow-md md:shadow-none hover:bg-gray-50">
                        <td className="p-4 md:px-6 md:py-4 block md:table-cell border-b md:border-b-0">
                            <div className="flex justify-between items-center md:block">
                                <span className="font-bold text-gray-500 md:hidden text-xs uppercase">Destino</span>
                                <span className="text-base font-semibold text-gray-900">{fare.destination}</span>
                            </div>
                        </td>
                        <td className="p-4 md:px-6 md:py-4 block md:table-cell border-b md:border-b-0">
                            <div className="flex justify-between items-center md:block">
                                <span className="font-bold text-gray-500 md:hidden text-xs uppercase">Região</span>
                                <span className="text-sm text-gray-600">{fare.region}</span>
                            </div>
                        </td>
                        <td className="p-4 md:px-6 md:py-4 block md:table-cell border-b md:border-b-0">
                             <div className="flex justify-between items-center md:block">
                                <span className="font-bold text-gray-500 md:hidden text-xs uppercase">Taxímetro</span>
                                <span className="text-sm text-gray-600">R$ {fare.meterValue.toFixed(2).replace('.', ',')}</span>
                            </div>
                        </td>
                        <td className="p-4 md:px-6 md:py-4 block md:table-cell border-b md:border-b-0 bg-yellow-50 md:bg-transparent rounded-b-xl md:rounded-none">
                            <div className="flex justify-between items-center md:block">
                                <span className="font-bold text-gray-500 md:hidden text-xs uppercase">Balcão</span>
                                <span className="text-lg text-gray-900 font-bold">R$ {fare.counterValue.toFixed(2).replace('.', ',')}</span>
                            </div>
                        </td>
                        {isAdmin && (
                            <td className="p-4 md:px-6 md:py-4 block md:table-cell text-right">
                                <div className="flex items-center justify-end space-x-3">
                                    <button onClick={() => handleEdit(fare)} className="text-indigo-600 p-1"><PencilIcon className="w-5 h-5" /></button>
                                    <button onClick={() => handleDelete(fare.id)} className="text-red-600 p-1"><TrashIcon className="w-5 h-5" /></button>
                                </div>
                            </td>
                        )}
                    </tr>
                )) : (
                    <tr><td colSpan={isAdmin ? 5 : 4} className="p-10 text-center text-gray-500">Nenhum resultado.</td></tr>
                )}
            </tbody>
        </table>
      </div>
    </div>
  );
};

