};


const FareTable: React.FC<FareTableProps> = ({ 
    fares, isAdmin, searchTerm, setSearchTerm, regionFilter, setRegionFilter, availableRegions,
    onAddFare, onUpdateFare, onDeleteFare, onImportFares 
}) => {
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [editingFare, setEditingFare] = useState<Fare | null>(null);
    const fileInputRef = useRef<HTMLInputElement>(null);

    const handleAdd = () => {
        if (!isAdmin) return;
        setEditingFare(null);
        setIsModalOpen(true);
    };

    const handleEdit = (fare: Fare) => {
        if (!isAdmin) return;
        setEditingFare(fare);
        setIsModalOpen(true);
    };

    const handleDelete = (id: string) => {
        if (!isAdmin) return;
        if (window.confirm('Tem certeza que deseja excluir esta corrida?')) {
            onDeleteFare(id);
        }
    };

    const handleSave = (fare: Fare) => {
        if (!isAdmin) return;
        if (editingFare) {
            onUpdateFare(fare);
        } else {
            onAddFare(fare);
        }
        setIsModalOpen(false);
        setEditingFare(null);
    };

    const handleImportClick = () => {
        if (!isAdmin) return;
        fileInputRef.current?.click();
    };

    const handleExport = () => {
        if (!isAdmin) return;
        if (fares.length === 0) {
            alert("Não há dados na tabela para exportar.");
            return;
        }

        const header = "Destino,Regiao,ValorTaximetro,ValorBalcao\n";
        const csvRows = fares.map(fare => {
            const destination = `"${fare.destination.replace(/"/g, '""')}"`;
            const region = `"${fare.region.replace(/"/g, '""')}"`;
            const meterValue = fare.meterValue.toFixed(2);
            const counterValue = fare.counterValue.toFixed(2);
            return [destination, region, meterValue, counterValue].join(',');
        }).join('\n');

        const csvContent = "\uFEFF" + header + csvRows;
        const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
        const link = document.createElement("a");
        const url = URL.createObjectURL(blob);
        link.setAttribute("href", url);
        const timestamp = new Date().toISOString().slice(0, 10).replace(/-/g, '');
        link.setAttribute("download", `export_tabela_taxi_${timestamp}.csv`);
        document.body.appendChild(link);
        link.click();

        document.body.removeChild(link);
        URL.revokeObjectURL(url);
    };

    const handleFileChange = (event: React.ChangeEvent<HTMLInputElement>) => {
        if (!isAdmin) return;
        const file = event.target.files?.[0];
        if (!file) return;

        const reader = new FileReader();
        reader.onload = (e) => {
            const text = e.target?.result as string;
            if (!text) return;

            try {
                const lines = text.split('\n').filter(line => line.trim() !== '');
                const newFares: Fare[] = lines.slice(1)
                    .map((line, index) => {
                        const [destination, region, meterValueStr, counterValueStr] = line.split(',');
                        if (!region || !destination || !meterValueStr || !counterValueStr) return null;

                        const meterValue = parseFloat(meterValueStr.trim());
                        const counterValue = parseFloat(counterValueStr.trim());

                        if (isNaN(meterValue) || isNaN(counterValue)) return null;

                        return {
                            id: `imported-${new Date().getTime()}-${index}`,
                            region: region.trim(),
                            destination: destination.trim(),
                            meterValue,
                            counterValue,
                        };
                    }).filter((fare): fare is Fare => fare !== null);

                if (newFares.length > 0) {
                    onImportFares(newFares);
                    setSearchTerm('');
                    alert(`${newFares.length} corridas importadas com sucesso!`);
                } else {
                    alert('Nenhuma corrida válida encontrada no arquivo.');
                }
            } catch (error) {
                console.error("Erro ao processar o arquivo CSV:", error);
                alert('Erro ao processar o arquivo CSV.');
            }
        };
        reader.readAsText(file);
        event.target.value = '';
    };

  return (
    <div className="bg-transparent">
       {isModalOpen && <FareModal fare={editingFare} onSave={handleSave} onClose={() => setIsModalOpen(false)} />}
      <div className="flex flex-col xl:flex-row justify-between items-center mb-6 gap-4 p-4 sm:p-6 bg-white rounded-xl shadow-md">
        <h2 className="text-xl sm:text-2xl font-bold text-gray-800 shrink-0">Bairro/Hotel</h2>
        <div className="w-full xl:w-auto flex flex-col xl:flex-row items-center gap-4">
            <div className="flex flex-col sm:flex-row gap-3 w-full xl:w-auto">
                {/* Busca por texto */}
                <div className="relative w-full xl:w-64">
                    <input
                        type="text"
                        placeholder="Buscar destino..."
                        value={searchTerm}
                        onChange={(e) => setSearchTerm(e.target.value)}
                        className="w-full pr-10 pl-4 py-2 text-base border border-gray-300 rounded-full focus:outline-none focus:ring-2 focus:ring-yellow-400 transition"
                    />
                    {searchTerm && (
                        <button 
                            onClick={() => setSearchTerm('')}
                            className="absolute right-3 top-1/2 -translate-y-1/2 p-1 text-gray-400 hover:text-gray-600 focus:outline-none"
                        >
                            <XIcon className="w-5 h-5" />
                        </button>
                    )}
                </div>

                {/* Filtro por região */}
                <div className="w-full xl:w-48">
                    <select
                        value={regionFilter}
                        onChange={(e) => setRegionFilter(e.target.value)}
                        className="w-full px-4 py-2 text-base border border-gray-300 rounded-full focus:outline-none focus:ring-2 focus:ring-yellow-400 bg-white transition cursor-pointer appearance-none"
                        style={{ backgroundImage: 'url("data:image/svg+xml;charset=utf-8,%3Csvg xmlns=\'http://www.w3.org/2000/svg\' fill=\'none\' viewBox=\'0 0 24 24\' stroke=\'%236B7280\'%3E%3Cpath stroke-linecap=\'round\' stroke-linejoin=\'round\' stroke-width=\'2\' d=\'M19 9l-7 7-7-7\'/%3E%3C/svg%3E")', backgroundRepeat: 'no-repeat', backgroundPosition: 'right 0.75rem center', backgroundSize: '1rem' }}
