      </div>

      <div className="mt-4 md:bg-white md:rounded-xl md:shadow overflow-hidden">
        <table className="min-w-full">
            <thead className="hidden md:table-header-group bg-gray-100">
                <tr>
                    <th className="px-6 py-4 text-left text-sm font-bold text-gray-600 uppercase">Destino</th>
                    <th className="px-6 py-4 text-left text-sm font-bold text-gray-600 uppercase">Região</th>
                    <th className="px-6 py-4 text-left text-sm font-bold text-gray-600 uppercase">Taxímetro</th>
                    <th className="px-6 py-4 text-left text-sm font-bold text-gray-600 uppercase">Balcão</th>
                    {isAdmin && <th className="px-6 py-4"></th>}
                </tr>
            </thead>
            <tbody className="divide-y divide-gray-200">
                {fares.length > 0 ? fares.map((fare) => (
                    <tr key={fare.id} className="block md:table-row mb-4 md:mb-0 bg-white rounded-xl shadow-md md:shadow-none hover:bg-gray-50">
                        <td className="p-4 md:px-6 md:py-4 block md:table-cell border-b md:border-b-0">
                            <div className="flex justify-between items-center md:block">
                                <span className="font-bold text-gray-500 md:hidden text-xs uppercase">Destino</span>
                                <span className="text-base font-semibold text-gray-900">{fare.destination}</span>
                            </div>
                        </td>
                        <td className="p-4 md:px-6 md:py-4 block md:table-cell border-b md:border-b-0">
                            <div className="flex justify-between items-center md:block">
                                <span className="font-bold text-gray-500 md:hidden text-xs uppercase">Região</span>
                                <span className="text-sm text-gray-600">{fare.region}</span>
