import React, { useState, useEffect } from 'react';
import type { Fare, User, LongTrip } from './types';
import Header from './components/Header';
import FareTable from './components/FareTable';
import LongTripCalculator from './components/LongTripCalculator';
import AuthPage from './components/AuthPage';
import UserManagement from './components/UserManagement';
import * as authService from './services/authService';
import * as fareService from './services/fareService';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(authService.getCurrentUser());
  const [activeView, setActiveView] = useState<'table' | 'calculator' | 'users'>('table');
  const [fares, setFares] = useState<Fare[]>(fareService.getFares());
  const [longTrips, setLongTrips] = useState<LongTrip[]>(fareService.getLongTrips());
  const [searchTerm, setSearchTerm] = useState<string>('');
  const [regionFilter, setRegionFilter] = useState<string>('');
  const [longTripSearchTerm, setLongTripSearchTerm] = useState<string>('');

  // Lazy initialization ensures we read from localStorage correctly on mount
  const [pricePerKm, setPricePerKm] = useState<number>(() => fareService.getPricePerKm());

  // Sync data across tabs/windows to ensure users receive updates
  useEffect(() => {
    const handleStorageChange = () => {
      setFares(fareService.getFares());
      setLongTrips(fareService.getLongTrips());
      setPricePerKm(fareService.getPricePerKm());
    };

    window.addEventListener('storage', handleStorageChange);
    return () => window.removeEventListener('storage', handleStorageChange);
  }, []);

  useEffect(() => {
    fareService.storeFares(fares);
  }, [fares]);

  useEffect(() => {
    fareService.storeLongTrips(longTrips);
  }, [longTrips]);

  useEffect(() => {
    // Only store if it's a valid number to prevent overwriting with bad data
    if (!isNaN(pricePerKm)) {
        fareService.storePricePerKm(pricePerKm);
    }
  }, [pricePerKm]);

  const handleLoginSuccess = (user: User) => {
    setCurrentUser(user);
  };

  const handleLogout = () => {
    authService.logout();
    setCurrentUser(null);
  };

  const uniqueRegions = React.useMemo(() => {
    const regions = fares.map(f => f.region).filter(r => r && r.trim() !== '');
    return Array.from(new Set(regions)).sort();
  }, [fares]);

  const filteredFares = React.useMemo(() => {
    return fares.filter(fare => {
      const matchesSearch = fare.destination.toLowerCase().includes(searchTerm.toLowerCase()) ||
                          fare.region.toLowerCase().includes(searchTerm.toLowerCase());
      const matchesRegion = regionFilter === '' || fare.region === regionFilter;
      return matchesSearch && matchesRegion;
    });
  }, [fares, searchTerm, regionFilter]);

  const filteredLongTrips = React.useMemo(() => {
    return longTrips.filter(trip =>
        trip.city.toLowerCase().includes(longTripSearchTerm.toLowerCase())
    );
  }, [longTrips, longTripSearchTerm]);

  const handleAddFare = (newFare: Fare) => {
    // Adiciona ao final da lista
    setFares(prevFares => [...prevFares, newFare]);
  };

  const handleUpdateFare = (updatedFare: Fare) => {
    setFares(prevFares => prevFares.map(f => (f.id === updatedFare.id ? updatedFare : f)));
  };

  const handleDeleteFare = (fareId: string) => {
    setFares(prevFares => prevFares.filter(f => f.id !== fareId));
  };

  const handleImportFares = (newFares: Fare[]) => {
    setFares(prevFares => [...prevFares, ...newFares]);
  };

  const handleAddLongTrip = (newTrip: LongTrip) => {
    // Adiciona ao final da lista
    setLongTrips(prev => [...prev, newTrip]);
  };

  const handleUpdateLongTrip = (updatedTrip: LongTrip) => {
    setLongTrips(prev => prev.map(t => (t.id === updatedTrip.id ? updatedTrip : t)));
  };

  const handleDeleteLongTrip = (tripId: string) => {
    setLongTrips(prev => prev.filter(t => t.id !== tripId));
  };

  if (!currentUser) {
    return <AuthPage onLoginSuccess={handleLoginSuccess} />;
  }

  const isAdmin = currentUser.role === 'admin';

  const renderActiveView = () => {
    switch (activeView) {
      case 'table':
        return (
          <FareTable
            fares={filteredFares}
            isAdmin={isAdmin}
            searchTerm={searchTerm}
            setSearchTerm={setSearchTerm}
            regionFilter={regionFilter}
            setRegionFilter={setRegionFilter}
            availableRegions={uniqueRegions}
            onAddFare={handleAddFare}
            onUpdateFare={handleUpdateFare}
            onDeleteFare={handleDeleteFare}
            onImportFares={handleImportFares}
          />
        );
      case 'calculator':
        return (
          <LongTripCalculator 
            isAdmin={isAdmin}
            pricePerKm={pricePerKm}
            setPricePerKm={setPricePerKm}
            longTrips={filteredLongTrips}
            searchTerm={longTripSearchTerm}
            setSearchTerm={setLongTripSearchTerm}
            onAddLongTrip={handleAddLongTrip}
            onUpdateLongTrip={handleUpdateLongTrip}
            onDeleteLongTrip={handleDeleteLongTrip}
          />
        );
      case 'users':
        return isAdmin ? <UserManagement /> : <p className="text-xl">Acesso negado.</p>;
      default:
        return null;
    }
  }

  return (
    <div className="min-h-screen bg-gray-50 text-gray-800 font-sans">
      <Header 
        user={currentUser}
        onLogout={handleLogout}
        activeView={activeView}
        onViewChange={setActiveView}
      />
      <main className="p-3 sm:p-6 lg:p-8 max-w-7xl mx-auto">
        {renderActiveView()}
      </main>
      <footer className="text-center p-6 text-gray-500 text-xs">
        <p>&copy; {new Date().getFullYear()} TABELA TÁXI. Todos os direitos reservados.</p>
      </footer>
    </div>
  );
};

export default App;

import React, { useState, useRef } from 'react';
import type { Fare } from '../types';
import { PlusIcon } from './icons/PlusIcon';
import { PencilIcon } from './icons/PencilIcon';
import { TrashIcon } from './icons/TrashIcon';
import { UploadIcon } from './icons/UploadIcon';
import { DownloadIcon } from './icons/DownloadIcon';
import { XIcon } from './icons/XIcon';

interface FareTableProps {
  fares: Fare[];
  isAdmin: boolean;
  searchTerm: string;
  setSearchTerm: (term: string) => void;
  regionFilter: string;
  setRegionFilter: (region: string) => void;
  availableRegions: string[];
  onAddFare: (fare: Fare) => void;
  onUpdateFare: (fare: Fare) => void;
  onDeleteFare: (id: string) => void;
  onImportFares: (fares: Fare[]) => void;
}

const FareModal: React.FC<{
  fare: Fare | null;
  onSave: (fare: Fare) => void;
  onClose: () => void;
}> = ({ fare, onSave, onClose }) => {
  const [formData, setFormData] = useState<Omit<Fare, 'id'>>({
    region: fare?.region || '',
    destination: fare?.destination || '',
    meterValue: fare?.meterValue || 0,
    counterValue: fare?.counterValue || 0,
  });

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const { name, value, type } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: type === 'number' ? parseFloat(value) || 0 : value,
    }));
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onSave({
      ...formData,
      id: fare?.id || new Date().toISOString(),
    });
  };

  return (
    <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-30 p-4 backdrop-blur-sm">
      <div className="bg-white rounded-lg shadow-xl p-6 w-full max-w-lg">
        <h2 className="text-xl font-bold mb-4">{fare ? 'Editar Corrida' : 'Adicionar Corrida'}</h2>
        <form onSubmit={handleSubmit}>
          <div className="space-y-3">
            <div>
                <label className="block text-xs font-bold text-gray-500 uppercase mb-1">Destino</label>
                <input type="text" name="destination" value={formData.destination} onChange={handleChange} placeholder="Ex: Aeroporto" className="w-full p-2.5 text-sm border rounded-lg focus:ring-2 focus:ring-yellow-400 outline-none" required />
            </div>
            <div>
                <label className="block text-xs font-bold text-gray-500 uppercase mb-1">Região</label>
                <input type="text" name="region" value={formData.region} onChange={handleChange} placeholder="Ex: Pampulha" className="w-full p-2.5 text-sm border rounded-lg focus:ring-2 focus:ring-yellow-400 outline-none" required />
            </div>
            <div className="grid grid-cols-2 gap-3">
              <div>
                  <label className="block text-xs font-bold text-gray-500 uppercase mb-1">Taxímetro</label>
                  <input type="number" name="meterValue" value={formData.meterValue} onChange={handleChange} placeholder="0.00" className="w-full p-2.5 text-sm border rounded-lg focus:ring-2 focus:ring-yellow-400 outline-none" step="0.01" required />
              </div>
              <div>
                  <label className="block text-xs font-bold text-gray-500 uppercase mb-1">Balcão</label>
                  <input type="number" name="counterValue" value={formData.counterValue} onChange={handleChange} placeholder="0.00" className="w-full p-2.5 text-sm border rounded-lg focus:ring-2 focus:ring-yellow-400 outline-none" step="0.01" required />
              </div>
            </div>
          </div>
          <div className="flex justify-end space-x-2 mt-6">
            <button type="button" onClick={onClose} className="px-4 py-2 text-sm bg-gray-100 rounded-lg font-bold hover:bg-gray-200 transition">Cancelar</button>
            <button type="submit" className="px-4 py-2 text-sm bg-yellow-400 text-gray-900 rounded-lg font-bold hover:bg-yellow-500 transition">Salvar</button>
          </div>
        </form>
      </div>
    </div>
  );
};


const FareTable: React.FC<FareTableProps> = ({ 
    fares, isAdmin, searchTerm, setSearchTerm, regionFilter, setRegionFilter, availableRegions,
    onAddFare, onUpdateFare, onDeleteFare, onImportFares 
}) => {
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [editingFare, setEditingFare] = useState<Fare | null>(null);
    const fileInputRef = useRef<HTMLInputElement>(null);

    const handleAdd = () => {
        if (!isAdmin) return;
        setEditingFare(null);
        setIsModalOpen(true);
    };

    const handleEdit = (fare: Fare) => {
        if (!isAdmin) return;
        setEditingFare(fare);
        setIsModalOpen(true);
    };

    const handleDelete = (id: string) => {
        if (!isAdmin) return;
        if (window.confirm('Excluir esta corrida?')) {
            onDeleteFare(id);
        }
    };

    const handleSave = (fare: Fare) => {
        if (!isAdmin) return;
        if (editingFare) {
            onUpdateFare(fare);
        } else {
            onAddFare(fare);
        }
        setIsModalOpen(false);
        setEditingFare(null);
    };

    const handleImportClick = () => {
        if (!isAdmin) return;
        fileInputRef.current?.click();
    };

    const handleExport = () => {
        if (!isAdmin) return;
        if (fares.length === 0) return;

        const header = "Destino,Regiao,ValorTaximetro,ValorBalcao\n";
        const csvRows = fares.map(fare => {
            const destination = `"${fare.destination.replace(/"/g, '""')}"`;
            const region = `"${fare.region.replace(/"/g, '""')}"`;
            const meterValue = fare.meterValue.toFixed(2);
            const counterValue = fare.counterValue.toFixed(2);
            return [destination, region, meterValue, counterValue].join(',');
        }).join('\n');

        const csvContent = "\uFEFF" + header + csvRows;
        const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
        const link = document.createElement("a");
        const url = URL.createObjectURL(blob);
        link.setAttribute("href", url);
        link.setAttribute("download", `tabela_taxi.csv`);
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
        URL.revokeObjectURL(url);
    };

    const handleFileChange = (event: React.ChangeEvent<HTMLInputElement>) => {
        if (!isAdmin) return;
        const file = event.target.files?.[0];
        if (!file) return;

        const reader = new FileReader();
        reader.onload = (e) => {
            const text = e.target?.result as string;
            if (!text) return;

            try {
                const lines = text.split('\n').filter(line => line.trim() !== '');
                const newFares: Fare[] = lines.slice(1)
                    .map((line, index) => {
                        const [destination, region, meterValueStr, counterValueStr] = line.split(',');
                        if (!region || !destination || !meterValueStr || !counterValueStr) return null;

                        const meterValue = parseFloat(meterValueStr.trim());
                        const counterValue = parseFloat(counterValueStr.trim());

                        if (isNaN(meterValue) || isNaN(counterValue)) return null;

                        return {
                            id: `imported-${Date.now()}-${index}`,
                            region: region.trim(),
                            destination: destination.trim(),
                            meterValue,
                            counterValue,
                        };
                    }).filter((fare): fare is Fare => fare !== null);

                if (newFares.length > 0) {
                    onImportFares(newFares);
                    setSearchTerm('');
                    alert(`${newFares.length} registros importados.`);
                }
            } catch (error) {
                alert('Erro ao processar CSV.');
            }
        };
        reader.readAsText(file);
        event.target.value = '';
    };

  return (
    <div className="bg-transparent">
       {isModalOpen && <FareModal fare={editingFare} onSave={handleSave} onClose={() => setIsModalOpen(false)} />}
      <div className="flex flex-col xl:flex-row justify-between items-center mb-4 gap-3 p-4 bg-white rounded-xl shadow-sm border border-gray-100">
        <h2 className="text-lg font-black text-gray-800 shrink-0">Bairro/Hotel</h2>
        <div className="w-full xl:w-auto flex flex-col sm:flex-row items-center gap-2">
            <div className="flex flex-col sm:flex-row gap-2 w-full">
                {/* Busca por texto com X */}
                <div className="relative w-full sm:w-60">
                    <input
                        type="text"
                        placeholder="Buscar destino..."
                        value={searchTerm}
