const FareTable: React.FC<FareTableProps> = ({ 
    fares, isAdmin, searchTerm, setSearchTerm, regionFilter, setRegionFilter, availableRegions,
    onAddFare, onUpdateFare, onDeleteFare, onImportFares 
}) => {
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [editingFare, setEditingFare] = useState<Fare | null>(null);
    const fileInputRef = useRef<HTMLInputElement>(null);

    const handleAdd = () => {
        if (!isAdmin) return;
        setEditingFare(null);
        setIsModalOpen(true);
    };

    const handleEdit = (fare: Fare) => {
        if (!isAdmin) return;
        setEditingFare(fare);
        setIsModalOpen(true);
    };

    const handleDelete = (id: string) => {
        if (!isAdmin) return;
        if (window.confirm('Excluir esta corrida da tabela?')) {
            onDeleteFare(id);
        }
    };

    const handleSave = (fare: Fare) => {
        if (!isAdmin) return;
        if (editingFare) {
            onUpdateFare(fare);
        } else {
            onAddFare(fare);
        }
        setIsModalOpen(false);
        setEditingFare(null);
    };

    const handleFileChange = (event: React.ChangeEvent<HTMLInputElement>) => {
        if (!isAdmin) return;
        const file = event.target.files?.[0];
        if (!file) return;

        const reader = new FileReader();
        reader.onload = (e) => {
            const text = e.target?.result as string;
            if (!text) return;

            try {
                const lines = text.split('\n').filter(line => line.trim() !== '');
                const newFares: Fare[] = lines.slice(1)
                    .map((line, index) => {
                        const parts = line.split(',');
                        if (parts.length < 4) return null;

                        const destination = parts[0]?.replace(/^"|"$/g, '').trim();
                        const region = parts[1]?.replace(/^"|"$/g, '').trim();
                        const meterValue = parseFloat(parts[2]);
                        const counterValue = parseFloat(parts[3]);

                        if (!destination || !region || isNaN(meterValue) || isNaN(counterValue)) return null;

                        return {
                            id: `imp-${Date.now()}-${index}`,
                            region,
                            destination,
                            meterValue,
                            counterValue,
                        };
                    }).filter((f): f is Fare => f !== null);

                if (newFares.length > 0) {
                    onImportFares(newFares);
                    alert(`${newFares.length} registros importados com sucesso.`);
                } else {
                    alert('Nenhum dado válido encontrado no CSV.');
                }
            } catch (error) {
                alert('Erro ao processar o arquivo CSV.');
            }
        };
        reader.readAsText(file);
        event.target.value = ''; // Limpa o input para permitir re-importação do mesmo arquivo
    };

    const handleExport = () => {
        if (!isAdmin || fares.length === 0) return;

        const header = "Destino,Regiao,ValorTaximetro,ValorBalcao\n";
        const csvRows = fares.map(fare => {
            return `"${fare.destination}","${fare.region}",${fare.meterValue.toFixed(2)},${fare.counterValue.toFixed(2)}`;
        }).join('\n');

        const blob = new Blob(["\uFEFF" + header + csvRows], { type: 'text/csv;charset=utf-8;' });
        const url = URL.createObjectURL(blob);
        const link = document.createElement("a");
        link.setAttribute("href", url);
        link.setAttribute("download", `tabela_taxi_${Date.now()}.csv`);
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
    };

  return (
    <div className="space-y-4">
       {isModalOpen && <FareModal key={editingFare?.id || 'new'} fare={editingFare} onSave={handleSave} onClose={() => setIsModalOpen(false)} />}

      {/* Controles de Filtro e Ação */}
      <div className="flex flex-col gap-3 p-3 bg-white rounded-xl shadow-sm border border-gray-100">
        <div className="flex items-center justify-between">
          <h2 className="text-sm font-black text-gray-700 uppercase tracking-widest">Bairro/Hotel</h2>
          {isAdmin && (
            <div className="flex items-center gap-1.5">
                <input type="file" ref={fileInputRef} onChange={handleFileChange} className="hidden" accept=".csv" />
                <button onClick={() => fileInputRef.current?.click()} className="p-1.5 text-blue-500 hover:bg-blue-50 rounded-lg" title="Importar"><UploadIcon className="w-4 h-4" /></button>
                <button onClick={handleExport} className="p-1.5 text-gray-500 hover:bg-gray-50 rounded-lg" title="Exportar"><DownloadIcon className="w-4 h-4" /></button>
                <button onClick={handleAdd} className="flex items-center bg-yellow-400 text-gray-900 px-3 py-1.5 rounded-lg text-[10px] font-black uppercase hover:bg-yellow-500 active:scale-95 transition-all">
                  <PlusIcon className="w-3 h-3 mr-1" /> Add
                </button>
            </div>
          )}
        </div>

        <div className="flex flex-col sm:flex-row gap-2">
            <div className="relative flex-1">
                <input
                    type="text"
                    placeholder="Buscar destino..."
                    value={searchTerm}
                    onChange={(e) => setSearchTerm(e.target.value)}
                    className="w-full pr-8 pl-3 py-2 text-xs border border-gray-200 rounded-lg focus:ring-2 focus:ring-yellow-400 outline-none bg-gray-50"
                />
                {searchTerm && (
                    <button 
                        onClick={() => setSearchTerm('')}
                        className="absolute right-2 top-1/2 -translate-y-1/2 p-1 text-gray-400 hover:text-gray-600"
                    >
                        <XIcon className="w-3.5 h-3.5" />
                    </button>
                )}
            </div>

            <div className="relative min-w-[140px]">
                <select
                    value={regionFilter}
                    onChange={(e) => setRegionFilter(e.target.value)}
                    className="w-full px-3 py-2 text-xs border border-gray-200 rounded-lg focus:ring-2 focus:ring-yellow-400 outline-none bg-gray-50 appearance-none cursor-pointer"
                >
                    <option value="">Todas as Regiões</option>
                    {availableRegions.map(region => (
                        <option key={region} value={region}>{region}</option>
                    ))}
                </select>
                <div className="absolute right-3 top-1/2 -translate-y-1/2 pointer-events-none text-gray-400">
                  <svg className="w-3 h-3" fill="currentColor" viewBox="0 0 20 20"><path d="M5.293 7.293a1 1 0 011.414 0L10 10.586l3.293-3.293a1 1 0 111.414 1.414l-4 4a1 1 0 01-1.414 0l-4-4a1 1 0 010-1.414z" /></svg>
                </div>
            </div>
        </div>
      </div>

      {/* Tabela de Resultados */}
      <div className="bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden">
        <table className="w-full text-left">
            <thead className="hidden md:table-header-group bg-gray-50">
                <tr>
                    <th className="px-4 py-3 text-[10px] font-black text-gray-400 uppercase">Destino</th>
                    <th className="px-4 py-3 text-[10px] font-black text-gray-400 uppercase">Região</th>
                    <th className="px-4 py-3 text-[10px] font-black text-gray-400 uppercase">Taxímetro</th>
                    <th className="px-4 py-3 text-[10px] font-black text-gray-400 uppercase">Balcão</th>
                    {isAdmin && <th className="px-4 py-3"></th>}
                </tr>
            </thead>
            <tbody className="divide-y divide-gray-50">
                {fares.length > 0 ? fares.map((fare) => (
                    <tr key={fare.id} className="block md:table-row hover:bg-yellow-50/20 transition-colors">
                        <td className="p-3 md:px-4 md:py-3 block md:table-cell">
                            <div className="flex justify-between items-start md:block">
                                <span className="font-bold text-[9px] text-gray-400 md:hidden uppercase mb-0.5">Destino</span>
                                <span className="text-xs font-bold text-gray-800 line-clamp-2">{fare.destination}</span>
                            </div>
                        </td>
                        <td className="px-3 py-1 md:px-4 md:py-3 block md:table-cell">
                            <div className="flex justify-between items-center md:block">
                                <span className="font-bold text-[9px] text-gray-400 md:hidden uppercase">Região</span>
                                <span className="text-[10px] text-gray-500 font-medium">{fare.region}</span>
                            </div>
                        </td>
                        <td className="px-3 py-1 md:px-4 md:py-3 block md:table-cell">
                             <div className="flex justify-between items-center md:block">
                                <span className="font-bold text-[9px] text-gray-400 md:hidden uppercase">Taxímetro</span>
                                <span className="text-[10px] text-gray-600 font-bold">R$ {fare.meterValue.toFixed(2).replace('.', ',')}</span>
                            </div>
                        </td>
                        <td className="p-3 md:px-4 md:py-3 block md:table-cell bg-yellow-50/30 md:bg-transparent">
                            <div className="flex justify-between items-center md:block">
                                <span className="font-bold text-[9px] text-gray-400 md:hidden uppercase">Balcão</span>
                                <span className="text-sm text-gray-900 font-black">R$ {fare.counterValue.toFixed(2).replace('.', ',')}</span>
                            </div>
                        </td>
                        {isAdmin && (
                            <td className="px-3 py-2 md:px-4 md:py-3 block md:table-cell text-right">
                                <div className="flex items-center justify-end space-x-2">
                                    <button onClick={() => handleEdit(fare)} className="p-1.5 text-blue-500 hover:bg-blue-50 rounded-lg"><PencilIcon className="w-3.5 h-3.5" /></button>
                                    <button onClick={() => handleDelete(fare.id)} className="p-1.5 text-red-500 hover:bg-red-50 rounded-lg"><TrashIcon className="w-3.5 h-3.5" /></button>
