                        )) : (
                            <tr><td colSpan={isAdmin ? 4 : 3} className="p-16 text-center text-gray-400 text-sm font-medium italic">Nenhum registro encontrado para a busca.</td></tr>
                        )}
                    </tbody>
                </table>
            </div>
        </div>
    );
};

