import React, { useState, useEffect } from 'react';
import type { Fare, User, LongTrip } from './types';
import Header from './components/Header';
import FareTable from './components/FareTable';
import LongTripCalculator from './components/LongTripCalculator';
import AuthPage from './components/AuthPage';
import UserManagement from './components/UserManagement';
import * as authService from './services/authService';
import * as fareService from './services/fareService';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(authService.getCurrentUser());
  const [activeView, setActiveView] = useState<'table' | 'calculator' | 'users'>('table');
  const [fares, setFares] = useState<Fare[]>(fareService.getFares());
  const [longTrips, setLongTrips] = useState<LongTrip[]>(fareService.getLongTrips());
  const [searchTerm, setSearchTerm] = useState<string>('');
  const [regionFilter, setRegionFilter] = useState<string>('');
  const [longTripSearchTerm, setLongTripSearchTerm] = useState<string>('');
  const [longTripKmSearchTerm, setLongTripKmSearchTerm] = useState<string>('');

  const [pricePerKm, setPricePerKm] = useState<number>(() => fareService.getPricePerKm());

  useEffect(() => {
    const handleStorageChange = () => {
      setFares(fareService.getFares());
      setLongTrips(fareService.getLongTrips());
      setPricePerKm(fareService.getPricePerKm());
    };

    window.addEventListener('storage', handleStorageChange);
    return () => window.removeEventListener('storage', handleStorageChange);
  }, []);

  useEffect(() => {
    fareService.storeFares(fares);
  }, [fares]);

  useEffect(() => {
    fareService.storeLongTrips(longTrips);
  }, [longTrips]);

  useEffect(() => {
    if (!isNaN(pricePerKm)) {
        fareService.storePricePerKm(pricePerKm);
    }
  }, [pricePerKm]);

  const handleLoginSuccess = (user: User) => {
    setCurrentUser(user);
  };

  const handleLogout = () => {
    authService.logout();
    setCurrentUser(null);
  };

  const uniqueRegions = React.useMemo(() => {
    const regions = fares.map(f => f.region).filter(r => r && r.trim() !== '');
    return Array.from(new Set(regions)).sort();
  }, [fares]);

  const filteredFares = React.useMemo(() => {
    return fares.filter(fare => {
      const matchesSearch = fare.destination.toLowerCase().includes(searchTerm.toLowerCase()) ||
                          fare.region.toLowerCase().includes(searchTerm.toLowerCase());
      const matchesRegion = regionFilter === '' || fare.region === regionFilter;
      return matchesSearch && matchesRegion;
    });
  }, [fares, searchTerm, regionFilter]);

  const filteredLongTrips = React.useMemo(() => {
    return longTrips.filter(trip => {
        // Busca por Nome da Cidade
        const matchesCity = trip.city.toLowerCase().includes(longTripSearchTerm.toLowerCase());

        // Refinamento da busca por KM: 
        // 1. Normalização (espaços, vírgulas)
        const kmInput = longTripKmSearchTerm.trim().replace(',', '.');
        const searchNum = parseFloat(kmInput);
        const isSearchNumValid = !isNaN(searchNum) && kmInput !== '';

        let matchesKm = true;
        if (kmInput !== '') {
            // Busca Exata/Texto: "50" em "150" ou "50.5" em "50.5"
            const stringIncludes = trip.kilometers.toString().includes(kmInput);

            // Busca Inteligente por Proximidade: ±2 KM de tolerância
            // Útil quando o GPS dá 52.3 mas o registro fixo é 51.0
            const proximityMatch = isSearchNumValid && Math.abs(trip.kilometers - searchNum) <= 2;

            matchesKm = stringIncludes || proximityMatch;
        }

        return matchesCity && matchesKm;
    });
  }, [longTrips, longTripSearchTerm, longTripKmSearchTerm]);

  const handleAddFare = (newFare: Fare) => {
    setFares(prevFares => [...prevFares, newFare]);
  };

  const handleUpdateFare = (updatedFare: Fare) => {
    setFares(prevFares => prevFares.map(f => (f.id === updatedFare.id ? updatedFare : f)));
  };

  const handleDeleteFare = (fareId: string) => {
    setFares(prevFares => prevFares.filter(f => f.id !== fareId));
  };

  const handleImportFares = (newFares: Fare[]) => {
    setFares(prevFares => [...prevFares, ...newFares]);
  };

  const handleAddLongTrip = (newTrip: LongTrip) => {
    setLongTrips(prev => [...prev, newTrip]);
  };

  const handleUpdateLongTrip = (updatedTrip: LongTrip) => {
    setLongTrips(prev => prev.map(t => (t.id === updatedTrip.id ? updatedTrip : t)));
  };

  const handleDeleteLongTrip = (tripId: string) => {
    setLongTrips(prev => prev.filter(t => t.id !== tripId));
  };

  if (!currentUser) {
    return <AuthPage onLoginSuccess={handleLoginSuccess} />;
  }

  const isAdmin = currentUser.role === 'admin';

  const renderActiveView = () => {
    switch (activeView) {
      case 'table':
        return (
          <FareTable
            fares={filteredFares}
            isAdmin={isAdmin}
            searchTerm={searchTerm}
            setSearchTerm={setSearchTerm}
            regionFilter={regionFilter}
            setRegionFilter={setRegionFilter}
            availableRegions={uniqueRegions}
            onAddFare={handleAddFare}
            onUpdateFare={handleUpdateFare}
            onDeleteFare={handleDeleteFare}
            onImportFares={handleImportFares}
          />
        );
      case 'calculator':
        return (
          <LongTripCalculator 
            isAdmin={isAdmin}
            pricePerKm={pricePerKm}
            setPricePerKm={setPricePerKm}
            longTrips={filteredLongTrips}
            searchTerm={longTripSearchTerm}
            setSearchTerm={setLongTripSearchTerm}
            kmSearchTerm={longTripKmSearchTerm}
            setKmSearchTerm={setLongTripKmSearchTerm}
            onAddLongTrip={handleAddLongTrip}
            onUpdateLongTrip={handleUpdateLongTrip}
            onDeleteLongTrip={handleDeleteLongTrip}
          />
        );
      case 'users':
        return isAdmin ? <UserManagement /> : <div className="text-center py-20 font-black text-gray-400 uppercase tracking-widest">Acesso Restrito ao Admin</div>;
      default:
        return null;
    }
  }

  return (
    <div className="min-h-screen bg-gray-50 text-gray-800 font-sans">
      <Header 
        user={currentUser}
        onLogout={handleLogout}
        activeView={activeView}
        onViewChange={setActiveView}
      />
      <main className="p-4 sm:p-6 lg:p-10 max-w-7xl mx-auto">
        {renderActiveView()}
      </main>
      <footer className="text-center p-8 text-gray-400 text-sm font-bold uppercase tracking-widest">
        <p>&copy; {new Date().getFullYear()} TABELA TÁXI • CONSULTA RÁPIDA</p>
      </footer>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import type { LongTrip, DistanceResult } from '../types';
import { PlusIcon } from './icons/PlusIcon';
import { PencilIcon } from './icons/PencilIcon';
import { TrashIcon } from './icons/TrashIcon';
import { MapPinIcon } from './icons/MapPinIcon';
import { CarIcon } from './icons/CarIcon';
import { XIcon } from './icons/XIcon';
import { getDistance } from '../services/geminiService';

const POPULAR_LOCATIONS = [
  "Aeroporto Internacional de Confins - Tancredo Neves",
  "Rodoviária de Belo Horizonte",
  "Shopping Cidade, Belo Horizonte",
  "BH Shopping, Belvedere",
  "Expominas, Gameleira",
  "Mineirão - Estádio Governador Magalhães Pinto",
  "Praça da Liberdade, Savassi",
  "Inhotim, Brumadinho",
  "Savassi, Belo Horizonte",
  "Centro, Belo Horizonte",
  "Vila da Serra, Nova Lima",
  "Lagoa Santa",
  "Vespasiano",
  "Santa Luzia",
  "Betim Centro"
];

interface LocationAutocompleteInputProps {
  label: string;
  value: string;
  onChange: (value: string) => void;
  placeholder: string;
  onUseCurrentLocation?: () => void;
}

const LocationAutocompleteInput: React.FC<LocationAutocompleteInputProps> = ({ label, value, onChange, placeholder, onUseCurrentLocation }) => {
  const [showSuggestions, setShowSuggestions] = useState(false);
  const [suggestions, setSuggestions] = useState<string[]>([]);
  const wrapperRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (value.trim() === '') {
      setSuggestions(POPULAR_LOCATIONS.slice(0, 4));
    } else {
      const filtered = POPULAR_LOCATIONS.filter(loc => 
        loc.toLowerCase().includes(value.toLowerCase()) && 
        loc.toLowerCase() !== value.toLowerCase()
      );
      setSuggestions(filtered.slice(0, 5));
    }
  }, [value]);

  useEffect(() => {
    function handleClickOutside(event: MouseEvent | TouchEvent) {
      if (wrapperRef.current && !wrapperRef.current.contains(event.target as Node)) {
        setShowSuggestions(false);
      }
    }
    document.addEventListener("mousedown", handleClickOutside);
    document.addEventListener("touchstart", handleClickOutside);
    return () => {
      document.removeEventListener("mousedown", handleClickOutside);
      document.removeEventListener("touchstart", handleClickOutside);
    };
  }, []);

  const handleSelect = (suggestion: string) => {
    onChange(suggestion);
    setShowSuggestions(false);
  };

  return (
    <div className="relative" ref={wrapperRef}>
        <div className="flex items-center justify-between mb-2">
            <label className="block text-sm font-black text-gray-500 uppercase tracking-tighter">{label}</label>
            {onUseCurrentLocation && (
                <button 
                    onClick={(e) => { e.preventDefault(); onUseCurrentLocation(); }}
                    className="text-xs font-black text-blue-600 uppercase hover:text-blue-800 flex items-center bg-blue-50 px-4 py-2 rounded-xl transition-colors"
                >
                    <MapPinIcon className="w-4 h-4 mr-1.5" /> USAR GPS
                </button>
            )}
        </div>
        <div className="relative">
            <span className="absolute inset-y-0 left-0 pl-4 flex items-center text-gray-400">
                <MapPinIcon className="w-5 h-5" />
            </span>
            <input 
                type="text" 
                value={value}
                onChange={(e) => {
                    onChange(e.target.value);
                    setShowSuggestions(true);
                }}
                onFocus={() => setShowSuggestions(true)}
                placeholder={placeholder}
                className="w-full pl-12 pr-12 py-4 text-base border border-gray-200 rounded-2xl focus:ring-2 focus:ring-blue-400 outline-none bg-white shadow-sm font-medium"
                autoComplete="off"
            />
            {value && (
              <button 
                  onClick={() => onChange('')}
                  className="absolute right-4 top-1/2 -translate-y-1/2 p-2 text-gray-300 hover:text-gray-500"
              >
                  <XIcon className="w-5 h-5" />
              </button>
            )}
        </div>

        {showSuggestions && suggestions.length > 0 && (
            <div className="absolute z-30 w-full bg-white mt-2 rounded-2xl shadow-2xl max-h-72 overflow-y-auto border border-gray-100 animate-in fade-in zoom-in duration-150">
                <ul>
                    {suggestions.map((suggestion, index) => (
                        <li 
                            key={index}
                            onMouseDown={(e) => { e.preventDefault(); handleSelect(suggestion); }}
                            className="px-5 py-4 hover:bg-blue-50 cursor-pointer text-base text-gray-700 border-b last:border-b-0 border-gray-50 font-bold"
                        >
                            {suggestion}
                        </li>
                    ))}
                </ul>
            </div>
        )}
    </div>
  );
};

interface LongTripModalProps {
  trip: LongTrip | null;
  onSave: (trip: LongTrip) => void;
  onClose: () => void;
}

const LongTripModal: React.FC<LongTripModalProps> = ({ trip, onSave, onClose }) => {
  const [formData, setFormData] = useState<Omit<LongTrip, 'id'>>({
    city: trip?.city || '',
    kilometers: trip?.kilometers || 0,
  });

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const { name, value, type } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: type === 'number' ? parseFloat(value) || 0 : value,
    }));
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onSave({
      ...formData,
      id: trip?.id || `lt-${Date.now()}-${Math.random().toString(36).substr(2, 5)}`,
    });
  };

  return (
    <div className="fixed inset-0 bg-black/70 flex items-center justify-center z-40 p-4 backdrop-blur-md">
      <div className="bg-white rounded-3xl shadow-2xl p-10 w-full max-w-lg animate-in zoom-in duration-200">
        <h2 className="text-2xl font-black mb-8 text-gray-800 uppercase tracking-tight">Novo Destino Fixo</h2>
        <form onSubmit={handleSubmit} className="space-y-6">
          <div>
              <label className="block text-xs font-black text-gray-400 uppercase mb-2 ml-1">Cidade / Destino</label>
              <input type="text" name="city" value={formData.city} onChange={handleChange} placeholder="Ex: Divinópolis" className="w-full p-4 text-base border border-gray-200 rounded-2xl focus:ring-2 focus:ring-yellow-400 outline-none shadow-sm" required />
          </div>
          <div>
              <label className="block text-xs font-black text-gray-400 uppercase mb-2 ml-1">Distância (KM)</label>
              <input type="number" name="kilometers" value={formData.kilometers} onChange={handleChange} placeholder="0" className="w-full p-4 text-base border border-gray-200 rounded-2xl focus:ring-2 focus:ring-yellow-400 outline-none shadow-sm font-black" step="0.1" required />
          </div>
          <div className="flex justify-end space-x-4 pt-8">
            <button type="button" onClick={onClose} className="px-8 py-4 text-sm font-black text-gray-500 hover:bg-gray-100 rounded-2xl transition-colors uppercase tracking-widest">Cancelar</button>
            <button type="submit" className="px-8 py-4 text-sm font-black bg-yellow-400 text-gray-900 rounded-2xl hover:bg-yellow-500 transition-colors shadow-lg uppercase tracking-widest">Confirmar</button>
          </div>
        </form>
      </div>
    </div>
  );
};

interface LongTripCalculatorProps {
  longTrips: LongTrip[];
  isAdmin: boolean;
  pricePerKm: number;
  setPricePerKm: (price: number) => void;
  searchTerm: string;
  setSearchTerm: (term: string) => void;
  kmSearchTerm: string;
  setKmSearchTerm: (term: string) => void;
  onAddLongTrip: (trip: LongTrip) => void;
  onUpdateLongTrip: (trip: LongTrip) => void;
  onDeleteLongTrip: (id: string) => void;
}

const LongTripCalculator: React.FC<LongTripCalculatorProps> = ({ 
    longTrips, isAdmin, pricePerKm, setPricePerKm, searchTerm, setSearchTerm, 
    kmSearchTerm, setKmSearchTerm,
    onAddLongTrip, onUpdateLongTrip, onDeleteLongTrip 
}) => {
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [editingTrip, setEditingTrip] = useState<LongTrip | null>(null);

    const [origin, setOrigin] = useState('Aeroporto Internacional de Confins - Tancredo Neves');
    const [destination, setDestination] = useState('');
    const [calculatedDistance, setCalculatedDistance] = useState<number | null>(null);
    const [isLoadingDistance, setIsLoadingDistance] = useState(false);
    const [distanceError, setDistanceError] = useState<string | null>(null);

    const handleUseCurrentLocation = () => {
        if (!navigator.geolocation) {
            alert("Navegador sem suporte a GPS.");
            return;
        }
        setIsLoadingDistance(true);
        navigator.geolocation.getCurrentPosition(
            (pos) => {
                setOrigin(`${pos.coords.latitude}, ${pos.coords.longitude}`);
                setIsLoadingDistance(false);
            },
            () => {
                alert("Erro ao obter GPS.");
                setIsLoadingDistance(false);
            },
            { enableHighAccuracy: true }
        );
    };

    const handleCalculateRoute = async () => {
        if (!origin.trim() || !destination.trim()) return;
        setIsLoadingDistance(true);
        setDistanceError(null);
        setCalculatedDistance(null);

        try {
            const result: DistanceResult = await getDistance(origin, destination);
            if (result.distance !== null && result.distance > 0) {
                setCalculatedDistance(result.distance);
                // SINCRONIZAÇÃO: Preenche automaticamente o filtro de KM para encontrar coincidências
                setKmSearchTerm(Math.floor(result.distance).toString());
            } else {
                setDistanceError("Rota não localizada. Tente endereços mais simples.");
            }
        } catch (error) {
            setDistanceError("Erro de comunicação com o servidor de mapas.");
        } finally {
            setIsLoadingDistance(false);
        }
    };

    const handleSave = (trip: LongTrip) => {
        if (editingTrip) onUpdateLongTrip(trip);
        else onAddLongTrip(trip);
        setIsModalOpen(false);
        setEditingTrip(null);
    };

    return (
        <div className="space-y-10">
            {isModalOpen && <LongTripModal key={editingTrip?.id || 'new'} trip={editingTrip} onSave={handleSave} onClose={() => setIsModalOpen(false)} />}

            {/* Calculadora Dinâmica - EXCLUSIVA PARA ADMIN */}
            {isAdmin && (
              <div className="bg-white rounded-3xl shadow-xl p-8 border border-gray-100 border-l-[12px] border-l-blue-600 animate-in slide-in-from-top-6 duration-500">
                  <div className="flex items-center justify-between mb-8">
                      <div className="flex items-center">
                        <div className="p-3 bg-blue-100 rounded-2xl mr-4">
                            <CarIcon className="w-8 h-8 text-blue-600" />
                        </div>
                        <h2 className="text-xl font-black text-gray-800 uppercase tracking-widest">Painel de Cálculo Inteligente</h2>
                      </div>
                      {isLoadingDistance && (
                        <div className="flex items-center space-x-2 px-4 py-2 bg-blue-50 rounded-full text-blue-600 text-sm font-black animate-pulse">
                          <span>IA CALCULANDO</span>
                        </div>
                      )}
                  </div>

                  <div className="grid grid-cols-1 md:grid-cols-2 gap-6 mb-10">
                      <LocationAutocompleteInput 
                          label="Ponto de Partida" 
                          value={origin} 
                          onChange={setOrigin} 
                          placeholder="Endereço ou local de saída..." 
                          onUseCurrentLocation={handleUseCurrentLocation}
                      />
                      <LocationAutocompleteInput 
                          label="Destino Final" 
                          value={destination} 
                          onChange={setDestination} 
                          placeholder="Cidade ou local de chegada..." 
                      />
                  </div>

                  <div className="flex flex-col items-center">
                      <button 
                          onClick={handleCalculateRoute}
                          disabled={isLoadingDistance}
                          className={`w-full md:w-auto px-16 py-5 rounded-2xl text-base font-black text-white uppercase shadow-2xl active:scale-95 transition-all flex items-center justify-center space-x-3 ${isLoadingDistance ? 'bg-gray-400 cursor-not-allowed' : 'bg-blue-600 hover:bg-blue-700'}`}
                      >
                          {isLoadingDistance ? (
                              <div className="w-6 h-6 border-4 border-white/30 border-t-white rounded-full animate-spin"></div>
                          ) : <MapPinIcon className="w-6 h-6" />}
                          <span>{isLoadingDistance ? 'Calculando Rota...' : 'Calcular com Google Maps'}</span>
                      </button>

                      {distanceError && (
                        <div className="mt-6 p-4 bg-red-50 border-2 border-red-100 rounded-2xl w-full max-w-md">
                          <p className="text-red-600 text-sm font-black text-center uppercase tracking-widest">{distanceError}</p>
                        </div>
                      )}

                      {calculatedDistance !== null && (
                          <div className="mt-10 text-center animate-in slide-in-from-bottom-8 duration-500 w-full max-w-xl">
                              <div className="bg-gray-50 p-4 rounded-2xl border border-gray-100 inline-block mb-6">
                                  <span className="text-gray-400 text-xs font-black uppercase tracking-widest mb-1 block">Distância Oficial</span>
                                  <span className="text-3xl font-black text-gray-800">{calculatedDistance.toFixed(1).replace('.', ',')} KM</span>
                              </div>

                              <div className="bg-green-600 rounded-[40px] p-10 shadow-2xl border-4 border-white ring-8 ring-green-50">
                                  <span className="text-white/80 text-sm font-black uppercase tracking-widest mb-3 block">Valor Total da Corrida</span>
                                  <p className="text-6xl font-black text-white drop-shadow-md">R$ {(calculatedDistance * pricePerKm).toFixed(2).replace('.', ',')}</p>
                              </div>
                          </div>
                      )}
                  </div>
              </div>
            )}

            {/* Listagem Fixa para todos os usuários */}
            <div className="space-y-6">
                <div className="flex flex-col xl:flex-row justify-between items-center gap-6 p-6 bg-white rounded-3xl shadow-md border border-gray-100">
                    <div className="flex items-center">
                        <div className="w-2 h-8 bg-yellow-400 rounded-full mr-4"></div>
                        <h2 className="text-xl font-black text-gray-800 uppercase tracking-widest">Tabela de Viagens Longas</h2>
                    </div>
                    <div className="flex flex-col sm:flex-row items-center gap-4 w-full xl:w-auto">
                        <div className="relative flex-1 sm:w-72">
                            <input
                                type="text"
                                placeholder="Filtrar por cidade..."
                                value={searchTerm}
                                onChange={(e) => setSearchTerm(e.target.value)}
                                className="w-full pr-12 pl-6 py-4 text-base border border-gray-200 rounded-2xl focus:ring-2 focus:ring-yellow-400 outline-none bg-gray-50 font-medium"
                            />
                            {searchTerm && (
                                <button onClick={() => setSearchTerm('')} className="absolute right-4 top-1/2 -translate-y-1/2 p-2 text-gray-400">
                                    <XIcon className="w-5 h-5" />
                                </button>
                            )}
                        </div>
                        <div className="relative flex-1 sm:w-48">
                            <input
                                type="text"
                                placeholder="KM..."
                                value={kmSearchTerm}
                                onChange={(e) => setKmSearchTerm(e.target.value)}
                                className="w-full pr-12 pl-6 py-4 text-base border border-gray-200 rounded-2xl focus:ring-2 focus:ring-yellow-400 outline-none bg-gray-50 font-black"
                            />
                            {kmSearchTerm && (
                                <button onClick={() => setKmSearchTerm('')} className="absolute right-4 top-1/2 -translate-y-1/2 p-2 text-gray-400">
                                    <XIcon className="w-5 h-5" />
                                </button>
                            )}
                        </div>
                        {isAdmin && (
                            <button
                                onClick={() => { setEditingTrip(null); setIsModalOpen(true); }}
                                className="bg-yellow-400 text-gray-900 font-black px-8 py-4 rounded-2xl text-sm uppercase hover:bg-yellow-500 shadow-lg flex items-center transition-transform active:scale-95"
                            >
                                <PlusIcon className="w-5 h-5 mr-2" /> Novo Registro
                            </button>
                        )}
                    </div>
                </div>

                {isAdmin && (
                    <div className="p-6 bg-white rounded-3xl shadow-sm border border-gray-100 flex flex-col sm:flex-row items-center justify-between gap-4">
                        <div className="flex flex-col">
                            <label className="text-xs font-black text-gray-400 uppercase tracking-widest mb-1">Custo por Quilômetro Rodado (Admin)</label>
                            <span className="text-[11px] text-blue-500 font-bold uppercase tracking-tight">Valor usado para multiplicar a distância e gerar o orçamento</span>
                        </div>
                        <div className="flex items-center border-4 border-yellow-100 rounded-2xl overflow-hidden bg-yellow-50 px-5">
                            <span className="text-lg text-yellow-600 font-black mr-3">R$</span>
                            <input
                                type="number"
                                value={pricePerKm}
                                onChange={(e) => setPricePerKm(parseFloat(e.target.value) || 0)}
                                className="w-24 py-4 text-lg font-black bg-transparent outline-none text-gray-800"
                                step="0.01"
                            />
                        </div>
                    </div>
                )}

                <div className="bg-white rounded-3xl shadow-xl border border-gray-100 overflow-hidden">
                    <table className="w-full text-left">
                        <thead className="hidden md:table-header-group bg-gray-50/50">
                            <tr>
